1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const FIRST_INSURANCE_MULTIPLIER = 1.1;
6	const CURSED_MULTIPLIER = 1.5;
7	const HIGH_ENCHANTMENT_MULTIPLIER = 1.3;
8	const LOYALTY_MULTIPLIER = 0.8;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const ADMIN_FEE = 5;
11	
12	const BASE_PRICE: Record<string, number> = {
13	  sword: 100,
14	  staff: 80,
15	  amulet: 60,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	function itemModifierMultiplier(item: Item): number {
21	  const cursed = item.cursed ? CURSED_MULTIPLIER : 1;
22	  const highEnchantment =
23	    (item.enchantment ?? 0) >= 5 ? HIGH_ENCHANTMENT_MULTIPLIER : 1;
24	  return cursed * highEnchantment;
25	}
26	
27	// MHPCO always rounds the euro value of a discounted/loaded price upward
28	// (in the office's favour). The toFixed(10) step strips IEEE-754 drift so
29	// values that are mathematically integer (e.g. 100 × 1.10 = 110) don't get
30	// bumped up a euro by a 110.00000000000001 representation.
31	function ceilInMhpcoFavor(value: number): number {
32	  return Math.ceil(Number(value.toFixed(10)));
33	}
34	
35	export function runScenario(scenario: unknown): unknown {
36	  const { customer, steps } = scenario as Scenario;
37	  const item = steps[0].items[0];
38	  const itemPrice = BASE_PRICE[item.type] * itemModifierMultiplier(item);
39	  const loyaltyMultiplier =
40	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_MULTIPLIER : 1;
41	  const premium =
42	    ceilInMhpcoFavor(itemPrice * loyaltyMultiplier * FIRST_INSURANCE_MULTIPLIER) +
43	    ADMIN_FEE;
44	  return { results: [{ premium }] };
45	}
